#include <bits/stdc++.h>
using namespace std;
int n,m,a[100005],dis[100005],dp[100005][11];
vector<int> g[100005]; 
queue<int> p;
int main(){
	cin>>n>>m;
	for(int i=1;i<=n;i++)
		cin>>a[i];
	for(int i=0;i<m;i++){
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		dis[v]++;
	} 
	for(int i=1;i<=n;i++){
		if(!dis[i])
			p.push(i);
		dp[i][a[i]]=1;
	}
	while(p.size()){
		int u=p.front();
		p.pop();
		for(int v:g[u]){
			for(int i=1;i<=a[v];i++)
				dp[v][a[v]]=max(dp[v][a[v]],dp[u][i]+1);
			for(int i=1;i<=10;i++)
				dp[v][i]=max(dp[v][i],dp[u][i]);
			if(!--dis[v])
				p.push(v);
		}
	}
	int ans=0;
	for(int i=1;i<=n;i++)
		for(int j=1;j<=10;j++)
			ans=max(ans,dp[i][j]);
	cout<<ans;
	return 0;
}
